class Solution:
    def spiralMatrixIII(self, rows: int, cols: int, rStart: int, cStart: int):
        result = []
        r, c = rStart, cStart
        # Brute-force: simulate step by step in E,S,W,N order
        dirs = [(0, 1), (1, 0), (0, -1), (-1, 0)]
        di = 0
        step = 1
        total = rows * cols
        while len(result) < total:
            for _ in range(2):
                dr, dc = dirs[di % 4]
                for _ in range(step):
                    if 0 <= r < rows and 0 <= c < cols:
                        result.append([r, c])
                    if len(result) == total:
                        return result
                    r += dr
                    c += dc
                di += 1
            step += 1
        return result

